let d = msg.payload;
if (typeof d === 'string') d = JSON.parse(d);


if (d.CO2 === undefined) {
    return null; 
}

// Jos CO2 löytyi, jatketaan normaalisti:
msg.payload = {
    "aikaleima": new Date(),
    "paikka": "simulaatio",
    "henkilomaara": d.pCount !== undefined ? d.pCount : 0,
    "co2": d.CO2,
    "lampotila": d.T,
    "kosteus": d.H,
    "kastepiste": d.DP
};

return msg;
